@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})
export class DashboardComponent implements OnInit {
  currentUser: any = null;
  statistics: any = {};
  recentBooks: any[] = [];
  userIssuedBooks: any[] = [];
  isLoading: boolean = true;

  constructor(private authService: AuthService, private bookService: BookService, private router: Router) {}

  ngOnInit(): void {
    this.currentUser = this.authService.getCurrentUser();
    this.loadDashboardData();
  }

  loadDashboardData(): void {
    this.statistics = this.bookService.getLibraryStatistics();
    this.recentBooks = this.bookService.getBooks().slice(0, 5);

    if (this.currentUser && this.currentUser.role === 'user') {
      this.userIssuedBooks = this.bookService.getIssuedBooksByUser(this.currentUser.id)
        .filter((book: any) => book.status === 'issued')
        .slice(0, 3);
    }

    this.isLoading = false;
  }

  isAdmin(): boolean {
    return this.authService.isAdmin();
  }

  refreshData(): void {
    this.isLoading = true;
    setTimeout(() => {
      this.loadDashboardData();
    }, 500);
  }

  getBookTitle(bookId: string): string {
    const book = this.bookService.getBookById(bookId);
    return book ? book.title : 'Unknown Book';
  }

  formatDate(date: Date | string): string {
    const d = new Date(date);
    return d.toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'short', 
      day: 'numeric' 
    });
  }

  isOverdue(dueDate: Date | string): boolean {
    return new Date(dueDate) < new Date();
  }

  getDueStatus(dueDate: Date | string): string {
    const due = new Date(dueDate);
    const today = new Date();
    const daysLeft = Math.ceil((due.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

    if (daysLeft < 0) {
      return `Overdue by ${Math.abs(daysLeft)} days`;
    } else if (daysLeft === 0) {
      return 'Due today';
    } else if (daysLeft === 1) {
      return 'Due tomorrow';
    } else {
      return `${daysLeft} days left`;
    }
  }

  navigateTo(route: string): void {
    this.router.navigate([route]);
  }
}
<div class="dashboard-container">
  <div class="dashboard-header">
    <h1>Dashboard</h1>
    <p>Welcome back, {{ currentUser?.name }}! 
      <span *ngIf="isAdmin()" class="admin-badge">Admin</span>
    </p>
    <button class="refresh-btn" (click)="refreshData()" [disabled]="isLoading">
      🔄 Refresh
    </button>
  </div>

  <div *ngIf="isLoading" class="loading">
    <div class="spinner"></div>
    <p>Loading dashboard...</p>
  </div>

  <div *ngIf="!isLoading" class="dashboard-content">
    <!-- Statistics Cards -->
    <div class="stats-grid">
      <div class="stat-card">
        <div class="stat-icon">📚</div>
        <div class="stat-content">
          <h3>{{ statistics.totalBooks }}</h3>
          <p>Total Books</p>
        </div>
      </div>

      <div class="stat-card">
        <div class="stat-icon">✅</div>
        <div class="stat-content">
          <h3>{{ statistics.availableBooks }}</h3>
          <p>Available Books</p>
        </div>
      </div>

      <div class="stat-card">
        <div class="stat-icon">📖</div>
        <div class="stat-content">
          <h3>{{ statistics.issuedBooks }}</h3>
          <p>Issued Books</p>
        </div>
      </div>

      <div class="stat-card">
        <div class="stat-icon">👥</div>
        <div class="stat-content">
          <h3>{{ statistics.totalUsers }}</h3>
          <p>Total Users</p>
        </div>
      </div>
    </div>

    <div class="dashboard-grid">
      <!-- Recent Books -->
      <div class="dashboard-section">
        <h2>📚 Recent Books</h2>
        <div class="book-list">
          <div *ngFor="let book of recentBooks" class="book-item">
            <div class="book-info">
              <h4>{{ book.title }}</h4>
              <p>by {{ book.author }}</p>
              <span class="book-category">{{ book.category }}</span>
            </div>
            <div class="book-quantity">
              <span class="available">{{ book.availableQuantity }}</span>
              <span>/</span>
              <span class="total">{{ book.quantity }}</span>
            </div>
          </div>
        </div>
        <div *ngIf="recentBooks.length === 0" class="empty-state">
          <p>No books available</p>
        </div>
      </div>

      <!-- User's Issued Books (only for regular users) -->
      <div *ngIf="!isAdmin()" class="dashboard-section">
        <h2>📖 My Issued Books</h2>
        <div class="issued-books-list">
          <div *ngFor="let issuedBook of userIssuedBooks" class="issued-book-item">
            <div class="issued-book-info">
              <h4>{{ getBookTitle(issuedBook.bookId) }}</h4>
              <p>Issued: {{ formatDate(issuedBook.issueDate) }}</p>
              <p>Due: {{ formatDate(issuedBook.dueDate) }}</p>
              <span class="due-status" [class.overdue]="isOverdue(issuedBook.dueDate)">
                {{ getDueStatus(issuedBook.dueDate) }}
              </span>
            </div>
          </div>
        </div>
        <div *ngIf="userIssuedBooks.length === 0" class="empty-state">
          <p>You haven't issued any books yet</p>
        </div>
      </div>

      <!-- Quick Actions for Admin -->
      <div *ngIf="isAdmin()" class="dashboard-section">
        <h2>⚡ Quick Actions</h2>
        <div class="quick-actions">
          <button class="action-btn" (click)="navigateTo('/book-management')">
            📝 Add New Book
          </button>
          <button class="action-btn" (click)="navigateTo('/book-search')">
            🔍 Search Books
          </button>
          <button class="action-btn" (click)="navigateTo('/book-history')">
            📊 View All History
          </button>
        </div>
      </div>
    </div>
  </div>
</div>
